#define ERR_UNKNOWNCOMMAND(nick, cmd)                  (PREFIX + "421 " + nick + " " + cmd + " :Unknown command" + CRLF)
#define ERR_NOMOTD(nick)                               (PREFIX + "422 " + nick + " :MOTD File is missing" + CRLF)
#define ERR_NOADMININFO(nick, server)                  (PREFIX + "423 " + nick + " " + server + " :No administrative info available" + CRLF)
#define ERR_FILEERROR(nick, fileop, file)              (PREFIX + "424 " + nick + " :File error doing " + fileop + " on " + file + CRLF)
#define ERR_NONICKNAMEGIVEN(nick)                      (PREFIX + "431 " + nick + " :No nickname given" + CRLF)
#define ERR_ERRONEUSNICKNAME(nick, badnick)            (PREFIX + "432 " + nick + " " + badnick + " :Erroneous nickname" + CRLF)
#define ERR_NICKNAMEINUSE(nick, target)                (PREFIX + "433 " + nick + " " + target + " :Nickname is already in use" + CRLF)
