#define ERR_SUMMONDISABLED(nick)                       (PREFIX + "445 " + nick + " :SUMMON has been disabled" + CRLF)
#define ERR_USERSDISABLED(nick)                        (PREFIX + "446 " + nick + " :USERS has been disabled" + CRLF)
#define ERR_NOTREGISTERED(nick)                        (PREFIX + "451 " + nick + " :You have not registered" + CRLF)
#define ERR_NEEDMOREPARAMS(nick, cmd)                  (PREFIX + "461 " + nick + " " + cmd + " :Not enough parameters" + CRLF)
