#define ERR_NOPERMFORHOST(nick)                        (PREFIX + "463 " + nick + " :Your host isn't among the privileged" + CRLF)
#define ERR_PASSWDMISMATCH(nick)                       (PREFIX + "464 " + nick + " :Password incorrect" + CRLF)
