#define ERR_NOCHANMODES(nick, channel)                 (PREFIX + "477 " + nick + " " + channel + " :Channel doesn't support modes" + CRLF)
#define ERR_BANLISTFULL(nick, channel, mode)           (PREFIX + "478 " + nick + " " + channel + " " + mode + " :Ban list is full" + CRLF)
#define ERR_NOPRIVILEGES(nick)                         (PREFIX + "481 " + nick + " :Permission Denied- You're not an IRC operator" + CRLF)
#define ERR_CHANOPRIVSNEEDED(nick, channel)            (PREFIX + "482 " + nick + " " + channel + " :You're not channel operator" + CRLF)
#define ERR_CANTKILLSERVER(nick)                       (PREFIX + "483 " + nick + " :You can't kill a server!" + CRLF)
#define ERR_RESTRICTED(nick)                           (PREFIX + "484 " + nick + " :Your connection is restricted!" + CRLF)
#define ERR_UNIQOPPRIVSNEEDED(nick)                    (PREFIX + "485 " + nick + " :You're not the original channel operator" + CRLF)
#define ERR_NOOPERHOST(nick)                           (PREFIX + "491 " + nick + " :No O-lines for your host" + CRLF)
#define ERR_UMODEUNKNOWNFLAG(nick)                     (PREFIX + "501 " + nick + " :Unknown MODE flag" + CRLF)
#define ERR_USERSDONTMATCH(nick)                       (PREFIX + "502 " + nick + " :Cannot change mode for other users" + CRLF)
#define ERR_INVALIDKEY(nick, channel)	               (PREFIX + "525 " + nick + " " + channel + " :Key is not well-formed" + CRLF)
#define ERR_INVALIDMODEPARAM(nk, ch, m, param, msg)    (PREFIX + "696 " + nk + " " + ch + " " + m + " " + param + " " + ch + " :" + msg + CRLF)


#define RPL_WELCOME(nick, user, host)                  (PREFIX + "001 " + nick + " :Welcome to the Internet Relay Network " + nick + "!" + user + "@" + host + CRLF)
#define RPL_YOURHOST(nick)                             (PREFIX + "002 " + nick + " :Your host is irc.server, running version 1.0" + CRLF)
#define RPL_CREATED(nick, creationTime)                (PREFIX + "003 " + nick + " :This server was created " + creationTime + CRLF)
#define RPL_MYINFO(nick)                               (PREFIX + "004 " + nick + " irc.server 1.0  iotkl" + CRLF)
#define RPL_NOTOPIC(nick, channel)                     (PREFIX + "331 " + nick + " " + channel + " :No topic is set" + CRLF)
#define RPL_TOPIC(nick, channel, topic)                (PREFIX + "332 " + nick + " " + channel + " :" + topic + CRLF)
#define RPL_TOPICWHOTIME(nick, ch, setter, t)          (PREFIX + "333 " + nick + " " + ch + " " + setter + " " + t + CRLF)
#define RPL_NAMREPLY(nick, channel, names)             (PREFIX + "353 " + nick + " = " + channel + " :" + names + CRLF)
#define RPL_ENDOFNAMES(nick, channel)                  (PREFIX + "366 " + nick + " " + channel + " :End of NAMES list" + CRLF)
#define RPL_MOTD(nick, text)                           (PREFIX + "372 " + nick + " :- " + text + CRLF)
#define RPL_MOTDSTART(nick)                            (PREFIX + "375 " + nick + " :- irc.server Message of the Day - " + CRLF)
#define RPL_ENDOFMOTD(nick)                            (PREFIX + "376 " + nick + " :End of /MOTD command" + CRLF)
#define RPL_UMODEIS(nick, modes)                       (PREFIX + "221 " + nick + " " + modes + CRLF)
#define RPL_CHANNELMODEIS(nick, ch, modes)             (PREFIX + "324 " + nick + " " + ch + " " + modes + CRLF)
#define RPL_CREATIONTIME(nick, ch, time)               (PREFIX + "329 " + nick + " " + ch + " " + time + CRLF)
#define RPL_INVITING(nick, target, channel)            (PREFIX + "341 " + nick + " " + target + " " + channel + CRLF)


#define RPL_NEWTOPIC(nick, channel, topic)             (nick + " TOPIC " + channel + " :" + topic + CRLF)
#define RPL_JOIN(user, channel)                        (user + " JOIN " + channel + CRLF)
#define RPL_PART(nk, ch, reason)                       (nk  + " PART " + ch + reason + CRLF)
#define RPL_QUIT(user, reason)                         (user + " QUIT :" + reason + CRLF)
#define RPL_PRIVMSG(sender, target, msg)               (sender + " PRIVMSG " + target + " :" + msg + CRLF)
#define RPL_NOTICE(sender, target, msg)                (sender + " NOTICE " + target + " :" + msg + CRLF)
#define RPL_NICK(oldnick, newnick)                     (oldnick + " NICK :" + newnick + CRLF)
#define RPL_KICK(by, channel, target, reason)          (by + " KICK " + channel + " " + target + " :" + reason + CRLF)
#define RPL_INVITE(by, target, channel)                (by + " INVITE " + target + " :" + channel + CRLF)
#define RPL_MODE(source, target, modes)                (source + " MODE " + target + " " + modes + CRLF)
#define RPL_PING(server)                               (server + " PONG " + server + CRLF)

#endif
